}
.title {
  font-weight: 700;
  font-size: 16px;
  color: #111827;
}
.actions {
  margin-top: 16px;
  display: flex;
  gap: 12px;
}
.btn {
  appearance: none;
  border: none;
  border-radius: 999px;
  padding: 10px 16px;
  font-size: 14px;
  cursor: pointer;
  background: #111827;
  color: #fff;
  transition: transform .2s ease;
}
.btn:hover { transform: translateY(-1px); }
.btn.secondary {
  background: #f3f4f6;
  color: #111827;
}
@media (max-width: 420px) {
